from dataclasses import dataclass
from typing import List, Dict

@dataclass
class UserProfile:
    username: str
    password: str

class LoginScreen:
    def __init__(self):
        self.users: List[UserProfile] = []
        self.current_user: UserProfile = None

    def add_user(self, username: str, password: str) -> None:
        user = UserProfile(username, password)
        self.users.append(user)

    def authenticate_user(self, username: str, password: str) -> bool:
        for user in self.users:
            if user.username == username and user.password == password:
                self.current_user = user
                return True
        return False

    def display_welcome_message(self) -> None:
        if self.current_user:
            print(f"Welcome {self.current_user.username}!")
        else:
            print("No user is currently logged in.")

def main() -> None:
    login_screen = LoginScreen()
    login_screen.add_user("user1", "password1")
    login_screen.add_user("user2", "password2")

    if login_screen.authenticate_user("user1", "password1"):
        login_screen.display_welcome_message()
    else:
        print("Authentication failed.")

if __name__ == "__main__":
    main()
